arguments.argument:
if !gDeltaDoTicks { exit; }
if image_xscale=1 {x+=moveSpdX}
else {x-=moveSpdX}
y+=moveSpdY

if image_xscale=1
{
  if x>=room_width+24 {instance_destroy()}
}
else
{
  if x<=-24 {instance_destroy()}
}

if bSpotted=0
{
  if checkScreenArea(x,y,2)=1
  {
    global.recBirdsSeen+=1
    bSpotted=1
  }
}
